public String extractGroupName(String className) {
    Matcher matcher = METHOD_AND_CLASS_NAME_PATTERN.matcher(className);

    if (matcher.matches()) {
        // Extract group using split and Arrays.asList
        String[] groups = matcher.groupArray(METHOD_AND_CLASS_NAME_PATTERN.groupCount());
        return groups != null && groups.length > 0 ? groups[1] : defaultString;
    } else {
        return defaultString;
    }
}

