public String customMethod(String input, int group, String defaultString) {
    // Check if the input is null
    if (input == null || input.isEmpty()) {
        return defaultString;
    }

    // Create a Pattern object for the regular expression
    Pattern pattern = Pattern.compile("your_regex_here"); // Replace "your_regex_here" with your actual regex

    // Create a Matcher object for the input string
    Matcher matcher = pattern.matcher(input);

    // Check if the input matches the pattern
    if (matcher.matches()) {
        // Return the group specified by the index
        return matcher.group(group);
    } else {
        // Return the default string
        return defaultString;
    }
}

