public String customGroupMatcher(String input, int groupIndex) {
    // Assuming 'matcher' is an instance of a regular expression matcher
    Matcher matcher = pattern.matcher(input);

    // Check if the input matches the pattern
    boolean hasMatch = matcher.find();

    // If there's no match, return the default string
    if (!hasMatch) {
        return defaultString;
    }

    // If there's a match, return the group at the specified index
    return matcher.group(groupIndex);
}

