public String customMatch(String input, int group, String defaultString) {
    // <<PLACEHOLDER>>
    Matcher matcher = Pattern.compile("(?<group>.*?)").matcher(input);

    if (matcher.find()) {
        return matcher.group(group);
    } else {
        return defaultString;
    }
}

